VALUES
  ('social-worker-moex-02111', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '試問以下那一個不是社會團體工作的實施原則？', '["重視社會工作的專業目標", "尊重團體的整體性", "注重個體的差異性", "必須是封閉性環境才能進行團體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02112', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體動力的描述，何者錯誤？', '["在團體中，個體與整體之間的關係並非是團體動力的重點", "在團體中的任何現象皆是屬於整體的一部分", "部分與部分之間具有互賴關係", "團體動力的眼光下團體是「有機的」整體"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02113', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Toseland和Rivas將團體分成處遇性和任務性團體，下列有關兩種團體特質的描述，那一項是正確的？', '["處遇性團體中的角色主要是互動的結果，任務性團體的角色可以是互動的結果，也可以被指定", "兩種團體都很重視自我表露，前者重視情感的表露，後者重視意見的表露", "兩種團體重視開放式溝通的程度是一致的，越開放溝通，越能夠達到目標", "兩種團體都很重視保密，對於保密內容和保密的嚴謹度要求都一致"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02114', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '為了讓特定的成員能夠在團體暢談敏感的議題（例如：少女的交友、家庭暴力受害經驗），團體的組成以 特定的年齡或性別為考量，排除其他特徵者，有關這樣的作法，下列何者正確？', '["因為排除其他特徵者，有歧視這些特徵者之嫌，應該避免", "因為考量團體的目標和運用的需求，這樣做很合理", "資源運用或分配並不公平，違背社會工作正義的倫理原則，應該避免", "這是團體效能和資源公平分配的倫理兩難議題，怎麼決定都不正確"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02115', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '你（妳）帶領一個病友支持團體，發現幾位成員組成次團體，下列那一種因應方式最適宜？', '["次團體不利於團體的動力和凝聚力，不該鼓勵", "成員可以從次團體得到支持，無論如何都應該予以鼓勵", "評估次團體的衝擊，如果是負向，必須在團體過程提出討論", "評估次團體的衝擊之後，如果屬於正向，才予以鼓勵"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02116', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '你（妳）帶領一個處遇團體，有兩位成員想和你（妳）進行團體之外的個別接觸，身為領導者，下列那 一種作法最適切？', '["一定要鼓勵，因為這類接觸提供了討論該成員參與團體或問題行為的機會", "不鼓勵，因為會讓其他成員嫉妒，也減損了團體的功能和目的", "鼓勵這類接觸，因為可以同時進行團體和個案工作，強化團體和個案工作交互的效果", "不一定要鼓勵或制止，凡事依據團體的目的和接觸的效益而定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02117', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體領導者對著團體說：「我對我們團體現在的情形有些擔心，你們當中有些人在講悄悄話，有些人沒有 在參與，有些人在做自己的事，沒有傾聽其他成員的分享，我想知道每個人對團體現在的情形有什麼感 覺。」這項回應比較貼近以下那一種技巧？', '["針對少數成員的干擾行為進行面質，減少他們的行為對整個團體的影響", "針對團體整體發言，中立地將當下行為加以描述，催促團體的過程", "重申團體的規範，並呼籲干擾的成員必須信守團體規範", "領導者真誠吐露自己對團體成員的感受，目的是減少負向行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02118', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體的凝聚力，下列何者正確？', '["凝聚力高的團體成員比較不容易真誠的表達內心的憤怒和說出彼此的衝突", "凝聚力不一定會增強成員自尊和相互接納，但可強化成員互相傾聽的意願", "凝聚力高的團體成員會努力遵守團體規範，有成員違反團體規範的時候會努力維護", "凝聚力高的團體成員不會過度依賴團體，因為團體成員展現很強的自主性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02119', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Yalom的團體工作強調重視「此時此刻」或「當下」（here and now），以下有關「此時此刻」的技巧何者', '["重視此時此刻團體的經驗，對其他成員、對領導者、對團體感受的表達", "重視團體當下 互動過程和事件，團體之外或成員過去生命事件都不重要", "重視當下過程的反思，檢視當下的互動關 係和行為", "重視當下的互動關係和方式，勝過於重視成員之間的言談內容"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02120', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '你（妳）服務的機構負責社區中的新住民關懷工作，因為新住民人數不斷的成長，機構無法獨立滿足案 主群的整體需求，你（妳）服務的機構開始和社區中另外兩個團體合作，發展出共同的願景，共同分擔 責任和分享資源和目標，這種服務機構之間建立的關係屬於下列何者？', '["聯繫會報", "協調", "聯盟", "共管"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
